#nullable enable // autogenerated

using System;
using System.Collections.Generic;
using MukioI18n;
using MVZ2Logic;
using MVZ2Logic.Definitions;
using MVZ2Logic.Localization;
using MVZ2Logic.Options;

namespace MVZ2.GameContent.Options
{
    [AutoOptionWidgetDefinition(LogicOptionWidgetNames.targetFramerate)]
    public class TargetFramerateOptionDropdown : OptionDropdownDefinition
    {
        public TargetFramerateOptionDropdown(string nsp, string name) : base(nsp, name)
        {
        }
        public override int GetValue(IOptionContext context)
        {
            var framerate = Global.Options.GetTargetFramerate();
            var index = Array.IndexOf(targetFramerates, framerate);
            if (index < 0)
            {
                index = 0;
            }
            return index;
        }
        public override void FillItems(IOptionContext context, List<string> items)
        {
            var localization = Global.Localization;
            foreach (int framerate in targetFramerates)
            {
                if (framerate == -1)
                {
                    items.Add(localization.GetTextParticular(FRAMERATE_DEFAULT, LogicStrings.CONTEXT_TARGET_FRAMERATE));
                }
                else
                {
                    items.Add(framerate.ToString());
                }
            }
        }
        public override void OnValueChanged(IOptionContext context, int index)
        {
            var framerate = targetFramerates[index];
            Global.Options.SetTargetFramerate(framerate);
            Global.Options.SaveOptions();
        }
        [TranslateMsg("FPS模式", LogicStrings.CONTEXT_TARGET_FRAMERATE)]
        public const string FRAMERATE_DEFAULT = "默认";

        public static readonly int[] targetFramerates = new int[]
        {
            -1,
            30,
            60,
            90,
            120,
            144
        };
    }
}
